const body = $input.first().json.body || $input.first().json;
const answers = body.form_response?.answers || body;

// Extract fields (adjust field refs to match your Typeform field IDs)
const fields = {
  CLIENT_ID: (answers.find(a => a.field?.ref === 'client_id') || {}).text || body.CLIENT_ID,
  CLIENT_NAME: (answers.find(a => a.field?.ref === 'client_name') || {}).text || body.CLIENT_NAME,
  NICHE: (answers.find(a => a.field?.ref === 'niche') || {}).text || body.NICHE,
  TARGET_AUDIENCE: (answers.find(a => a.field?.ref === 'target_audience') || {}).text || body.TARGET_AUDIENCE,
  TONE_GUIDE: (answers.find(a => a.field?.ref === 'tone_guide') || {}).text || body.TONE_GUIDE,
  CTA_KEYWORD: (answers.find(a => a.field?.ref === 'cta_keyword') || {}).text || body.CTA_KEYWORD,
  TIMEZONE: (answers.find(a => a.field?.ref === 'timezone') || {}).text || 'Europe/Paris',
  FREE_RESOURCE_URL: (answers.find(a => a.field?.ref === 'free_resource_url') || {}).url || body.FREE_RESOURCE_URL,
  BRAND_TERMS_TO_AVOID: ((answers.find(a => a.field?.ref === 'brand_terms') || {}).text || '').split(',').map(t => t.trim()).filter(Boolean)
};

// Validation
const errors = [];
if (!fields.CLIENT_ID || !/^c_[a-z0-9_]{2,20}$/.test(fields.CLIENT_ID)) errors.push('CLIENT_ID must match c_[a-z0-9_]{2,20}');
if (!fields.CLIENT_NAME) errors.push('CLIENT_NAME required');
if (!fields.NICHE) errors.push('NICHE required');
if (!fields.TARGET_AUDIENCE) errors.push('TARGET_AUDIENCE required');
if (!fields.TONE_GUIDE) errors.push('TONE_GUIDE required');
if (!fields.CTA_KEYWORD || fields.CTA_KEYWORD.length < 2 || fields.CTA_KEYWORD.length > 15) errors.push('CTA_KEYWORD must be 2-15 chars');
if (!fields.FREE_RESOURCE_URL || !/^https?:\/\/.+/.test(fields.FREE_RESOURCE_URL)) errors.push('FREE_RESOURCE_URL must be valid URL');

if (errors.length > 0) {
  throw new Error('Validation failed: ' + errors.join('; '));
}

// Compute week_start (most recent Monday)
const now = new Date();
const day = now.getDay();
const diff = (day === 0 ? -6 : 1 - day);
const monday = new Date(now);
monday.setDate(now.getDate() + diff);
fields.WEEK_START = monday.toISOString().split('T')[0];

return [{ json: fields }];

const clientId = $('Validate & Parse Payload').item.json.CLIENT_ID;
const tz = $('Validate & Parse Payload').item.json.TIMEZONE;
// Mon=1 Tue=2 Wed=3 Thu=4 Fri=5
const scheduleRows = [1,2,3,4,5].map(dow => ({
  client_id: clientId,
  day_of_week: dow,
  time_local: '08:30:00',
  timezone: tz,
  active: true
}));
return [{ json: { scheduleRows } }];
